generated_test_src:
import { test, expect } from "vitest";
import { getLatestVersion } from "./impl";

test("getLatestVersion returns the highest semver version and handles edge cases", () => {
  // Empty array should return undefined
  expect(getLatestVersion([])).toBeUndefined();

  // Single element array returns that element
  expect(getLatestVersion(["1.2.3"])).toBe("1.2.3");

  // Multiple versions: highest is 2.0.0
  expect(getLatestVersion(["1.0.0", "2.0.0", "1.5.0"])).toBe("2.0.0");

  // Prerelease versions are lower than release versions
  expect(getLatestVersion(["1.0.0", "1.0.1-beta", "1.0.1"])).toBe("1.0.1");

  // Tie: equal versions should return the first occurrence (since comparison uses > 0)
  expect(getLatestVersion(["1.0.0", "1.0.0"])).toBe("1.0.0");

  // Versions with different major, minor, patch
  expect(getLatestVersion(["2.1.0", "2.0.9", "1.9.9"])).toBe("2.1.0");

  // Prerelease vs release with same numeric parts
  expect(getLatestVersion(["1.0.0-alpha", "1.0.0"])).toBe("1.0.0");

  // Multiple prereleases: highest numeric prerelease wins? Reference compares only numeric parts and then prerelease flag.
  // Since both have prerelease flag, they are considered equal in prerelease status, so numeric comparison decides.
  // But reference's compareVersions only extracts numeric parts and then checks for '-' presence.
  // For "1.0.0-alpha" and "1.0.0-beta", numeric parts are same, both have prerelease -> returns 0.
  // Then getLatestVersion would keep the first one (since >0 is false). So we test that.
  expect(getLatestVersion(["1.0.0-alpha", "1.0.0-beta"])).toBe("1.0.0-alpha");
});

